patch:
diff --git a/llvm/lib/Transforms/IPO/FunctionAttrs.cpp b/llvm/lib/Transforms/IPO/FunctionAttrs.cpp
index f918d7e059b6..dba1fa60f263 100644
--- a/llvm/lib/Transforms/IPO/FunctionAttrs.cpp
+++ b/llvm/lib/Transforms/IPO/FunctionAttrs.cpp
@@ -677,9 +677,11 @@ ArgumentAccessInfo getArgumentAccessInfo(const Instruction *I,
     auto *ConstantLength = dyn_cast<ConstantInt>(Length);
     if (ConstantLength && Offset &&
         ConstantLength->getValue().isStrictlyPositive()) {
-      return ConstantRange(
-          APInt(64, *Offset, true),
-          APInt(64, *Offset + ConstantLength->getSExtValue(), true));
+      APInt Lower = APInt(64, *Offset, true);
+      APInt Upper = APInt(64, *Offset + ConstantLength->getSExtValue(), true);
+      if (Lower.slt(Upper)) {
+        return ConstantRange(Lower, Upper);
+      }
     }
     return std::nullopt;
   };

